# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

import os
import secrets
import sqlite3
from datetime import datetime, timedelta
from flask import Flask, request, jsonify
from flask_mail import Mail, Message
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Configuration
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'dev-secret-key-change-in-production')
app.config['MAIL_SERVER'] = os.environ.get('MAIL_SERVER', 'smtp.gmail.com')
app.config['MAIL_PORT'] = int(os.environ.get('MAIL_PORT', 587))
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = os.environ.get('MAIL_USERNAME', '')
app.config['MAIL_PASSWORD'] = os.environ.get('MAIL_PASSWORD', '')
app.config['MAIL_DEFAULT_SENDER'] = os.environ.get('MAIL_DEFAULT_SENDER', 'noreply@example.com')
app.config['FRONTEND_URL'] = os.environ.get('FRONTEND_URL', 'http://localhost:3000')

mail = Mail(app)

DATABASE = 'password_reset.db'


def get_db():
    """Get a database connection."""
    conn = sqlite3.connect(DATABASE)
    conn.row_factory = sqlite3.Row
    return conn


def init_db():
    """Initialize the database with required tables."""
    conn = get_db()
    cursor = conn.cursor()

    # Users table (for MVP, simple user storage)
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')

    # Password reset tokens table
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS password_reset_tokens (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT NOT NULL,
            token_hash TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            expires_at TIMESTAMP NOT NULL,
            used INTEGER DEFAULT 0,
            FOREIGN KEY (email) REFERENCES users(email)
        )
    ''')

    conn.commit()
    conn.close()


def generate_reset_token():
    """Generate a cryptographically secure random token."""
    return secrets.token_urlsafe(32)


def send_reset_email(email, token):
    """Send password reset email with the reset link."""
    reset_url = f"{app.config['FRONTEND_URL']}/reset-password?token={token}&email={email}"

    msg = Message(
        subject='Password Reset Request',
        recipients=[email],
        html=f'''
        <h2>Password Reset Request</h2>
        <p>You requested a password reset. Click the link below to reset your password:</p>
        <p><a href="{reset_url}">Reset Your Password</a></p>
        <p>This link will expire in 1 hour.</p>
        <p>If you didn't request this, please ignore this email.</p>
        '''
    )

    try:
        mail.send(msg)
        return True
    except Exception as e:
        print(f"Failed to send email: {e}")
        return False


@app.route('/api/register', methods=['POST'])
def register():
    """Register a new user (helper endpoint for testing)."""
    data = request.get_json()

    if not data or not data.get('email') or not data.get('password'):
        return jsonify({'error': 'Email and password are required'}), 400

    email = data['email'].strip().lower()
    password = data['password']

    conn = get_db()
    cursor = conn.cursor()

    try:
        password_hash = generate_password_hash(password)
        cursor.execute(
            'INSERT INTO users (email, password_hash) VALUES (?, ?)',
            (email, password_hash)
        )
        conn.commit()
        return jsonify({'message': 'User registered successfully'}), 201
    except sqlite3.IntegrityError:
        return jsonify({'error': 'Email already registered'}), 409
    finally:
        conn.close()


@app.route('/api/password-reset/request', methods=['POST'])
def request_password_reset():
    """Request a password reset link. Generates token and sends email."""
    data = request.get_json()

    if not data or not data.get('email'):
        return jsonify({'error': 'Email is required'}), 400

    email = data['email'].strip().lower()

    conn = get_db()
    cursor = conn.cursor()

    try:
        # Check if user exists
        cursor.execute('SELECT id FROM users WHERE email = ?', (email,))
        user = cursor.fetchone()

        if not user:
            # Return success even if user doesn't exist (security: don't reveal registered emails)
            return jsonify({
                'message': 'If an account with that email exists, a reset link has been sent.'
            }), 200

        # Invalidate any existing unused tokens for this email
        cursor.execute(
            'UPDATE password_reset_tokens SET used = 1 WHERE email = ? AND used = 0',
            (email,)
        )

        # Generate new token
        token = generate_reset_token()
        token_hash = generate_password_hash(token)
        expires_at = datetime.utcnow() + timedelta(hours=1)

        # Store token in database
        cursor.execute(
            'INSERT INTO password_reset_tokens (email, token_hash, expires_at) VALUES (?, ?, ?)',
            (email, token_hash, expires_at.isoformat())
        )
        conn.commit()

        # Send reset email
        email_sent = send_reset_email(email, token)

        if not email_sent:
            # Log the failure but still return generic message
            print(f"Warning: Failed to send reset email to {email}")
            # In development, return the token for testing
            if app.debug:
                return jsonify({
                    'message': 'If an account with that email exists, a reset link has been sent.',
                    'debug_token': token,
                    'debug_note': 'Email sending failed. Token provided for testing only.'
                }), 200

        return jsonify({
            'message': 'If an account with that email exists, a reset link has been sent.'
        }), 200

    except Exception as e:
        conn.rollback()
        print(f"Error in password reset request: {e}")
        return jsonify({'error': 'An error occurred. Please try again later.'}), 500
    finally:
        conn.close()


@app.route('/api/password-reset/verify', methods=['POST'])
def verify_reset_token():
    """Verify that a reset token is valid (optional: for frontend to check before showing form)."""
    data = request.get_json()

    if not data or not data.get('email') or not data.get('token'):
        return jsonify({'error': 'Email and token are required'}), 400

    email = data['email'].strip().lower()
    token = data['token']

    conn = get_db()
    cursor = conn.cursor()

    try:
        # Get all unused tokens for this email
        cursor.execute(
            'SELECT token_hash, expires_at FROM password_reset_tokens WHERE email = ? AND used = 0',
            (email,)
        )
        tokens = cursor.fetchall()

        for stored_token in tokens:
            if check_password_hash(stored_token['token_hash'], token):
                # Check expiration
                expires_at = datetime.fromisoformat(stored_token['expires_at'])
                if datetime.utcnow() > expires_at:
                    return jsonify({'error': 'Reset token has expired'}), 400
                return jsonify({'valid': True, 'message': 'Token is valid'}), 200

        return jsonify({'error': 'Invalid or expired reset token'}), 400

    except Exception as e:
        print(f"Error verifying token: {e}")
        return jsonify({'error': 'An error occurred. Please try again later.'}), 500
    finally:
        conn.close()


@app.route('/api/password-reset/reset', methods=['POST'])
def reset_password():
    """Reset the password using the token."""
    data = request.get_json()

    if not data or not data.get('email') or not data.get('token') or not data.get('new_password'):
        return jsonify({'error': 'Email, token, and new password are required'}), 400

    email = data['email'].strip().lower()
    token = data['token']
    new_password = data['new_password']

    # Basic password validation
    if len(new_password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters long'}), 400

    conn = get_db()
    cursor = conn.cursor()

    try:
        # Get all unused tokens for this email
        cursor.execute(
            'SELECT id, token_hash, expires_at FROM password_reset_tokens WHERE email = ? AND used = 0',
            (email,)
        )
        tokens = cursor.fetchall()

        valid_token_id = None
        for stored_token in tokens:
            if check_password_hash(stored_token['token_hash'], token):
                # Check expiration
                expires_at = datetime.fromisoformat(stored_token['expires_at'])
                if datetime.utcnow() > expires_at:
                    return jsonify({'error': 'Reset token has expired. Please request a new one.'}), 400
                valid_token_id = stored_token['id']
                break

        if not valid_token_id:
            return jsonify({'error': 'Invalid or expired reset token'}), 400

        # Update password
        new_password_hash = generate_password_hash(new_password)
        cursor.execute(
            'UPDATE users SET password_hash = ? WHERE email = ?',
            (new_password_hash, email)
        )

        # Mark token as used
        cursor.execute(
            'UPDATE password_reset_tokens SET used = 1 WHERE id = ?',
            (valid_token_id,)
        )

        # Also invalidate all other tokens for this user
        cursor.execute(
            'UPDATE password_reset_tokens SET used = 1 WHERE email = ? AND used = 0',
            (email,)
        )

        conn.commit()

        return jsonify({'message': 'Password has been reset successfully'}), 200

    except Exception as e:
        conn.rollback()
        print(f"Error resetting password: {e}")
        return jsonify({'error': 'An error occurred. Please try again later.'}), 500
    finally:
        conn.close()


